INSERT INTO products (id, sku, title_it, title_en, category_id, price, stock_quantity, box_quantity, description_it, description_en, image_urls, is_accessory, attributes, created_at, is_active, price_tiers) VALUES ('29641ecd-5691-4254-aee1-568b684a6f27', 'SC125.0186', 'Sandy', NULL, NULL, 0.46, 0, 100, '<p>Il flacone&nbsp;in plastica Sandy 125 ml presenta&nbsp;un design equilibrato e slanciato, ideale per prodotti cosmetici viso, corpo, capelli e detergenza.</p>', '<p>Sandy 125 ml plastic bottle&nbsp;has&nbsp;a well-balanced and slim design that makes it&nbsp;the ideal packaging solution&nbsp;for cosmetic, personal care and haircare products.</p>', '["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/SC125.0186.jpg"]', FALSE, '{"ml": 125, "colore": "Bianco", "finitura": "Soft-touch", "categoria": "Flaconi plastica", "materiale": "PE HDLD soft touch", "imboccatura": "FLIPTOP Venus"}', '2026-06-16T09:26:04.504484+00:00', TRUE, '[]');
